  } else {
    print('You are too young to vote.');
  }
}

void main() {
  int score = 85;

  if (score >= 90) {
    print('Grade: A');
  } else if (score >= 80) {
    print('Grade: B');
  } else if (score >= 70) {
    print('Grade: C');
  } else {
    print('Grade: F');
  }
}

void main() {
  int age = 20;
  bool hasID = true;

  if (age >= 18) {
    if (hasID) {
      print('You can enter the club.');
    } else {
      print('You need an ID.');
    }
  } else {
    print('You are too young.');
  }
}

void main() {
  int age = 20;
  String status = (age >= 18) ? 'Adult' : 'Minor';
  print(status); // Adult
}

void main() {
  String grade = 'B';

  switch (grade) {
    case 'A':
      print('Excellent!');
      break;
    case 'B':
      print('Good job!');
      break;
    case 'C':
      print('Fair.');
      break;
    case 'D':
    case 'F':
      print('Need improvement.');
      break;
    default:
      print('Invalid grade.');
  }
}

enum TrafficLight { red, yellow, green }

void main() {
  TrafficLight light = TrafficLight.red;

  switch (light) {
    case TrafficLight.red:
      print('Stop');
      break;
    case TrafficLight.yellow:
      print('Caution');
      break;
    case TrafficLight.green:
      print('Go');
      break;
  }
}

void main() {
  String? name;

  // Using ?? to provide default value
  String displayName = name ?? 'Guest';
  print(displayName); // Guest

  // Using ?. for safe access
  print(name?.length); // null
}

void main() {
  int temperature = 25;

  // if-else chain
  if (temperature > 30) {
    print('It\'s hot!');
  } else if (temperature > 20) {
    print('Nice weather.');
  } else {
    print('It\'s cold.');
  }

  // Ternary
  String weather = (temperature > 25) ? 'Warm' : 'Cool';
  print(weather);

  // Switch with enum
  enum Day { monday, tuesday, wednesday, thursday, friday, saturday, sunday }
  Day today = Day.wednesday;

  switch (today) {
    case Day.saturday:
    case Day.sunday:
      print('Weekend!');
      break;
    default:
      print('Weekday.');
  }
}

